package com.indianservers.aiexplorer.learning.ncert.assessment
import com.indianservers.aiexplorer.phase3.assessment.*
import com.indianservers.aiexplorer.learningintelligence.model.*
object MathematicsAssessmentAdapter:SubjectCriterionValidator{private val symbolic=SafeSymbolicEquivalenceEngine();override fun validate(criterion:StepCriterion,attempt:CriterionAttempt,prior:Map<String,CriterionScore>):CriterionValidation=when(criterion.validatorId){"linear-formula"->CriterionValidation(attempt.answer.contains('='),feedback="State an equation preserving equality.");"linear-transform"->{val r=symbolic.validate("x=3",attempt.answer);CriterionValidation(r.equivalent,r.equivalent,feedback=r.issueCode?:"Equivalent transformation.",corrected="x=3")};"proof-reason"->CriterionValidation(attempt.answer.contains("because",true)||attempt.answer.contains("property",true),feedback="Connect statement to a named reason.");else->CriterionValidation(attempt.answer.isNotBlank(),feedback="Mathematics response checked locally.")}}
